package llmgen

import (
	"bytes"
	"fmt"
	"go/format"
	"strings"
	"unicode"

	"github.com/shipq/shipq/codegen/llmcompile"
)

// GenerateToolRegistry generates a zz_generated_registry.go file for a single
// tool package. The generated file contains:
//
//  1. A JSON Schema variable for each tool's input type.
//  2. A typed dispatcher function for each tool (no reflection at runtime).
//  3. A Registry() function that returns an *llm.Registry with all tools.
//
// The generated dispatchers call the user's function directly with correct types,
// producing better stack traces and faster execution than the reflection-based
// ToolFunc wrapper from the registration DSL.
func GenerateToolRegistry(pkg llmcompile.SerializedToolPackage, modulePath string) ([]byte, error) {
	var buf bytes.Buffer

	llmPkg := modulePath + "/shipq/lib/llm"

	buf.WriteString("// Code generated by shipq. DO NOT EDIT.\n")
	fmt.Fprintf(&buf, "package %s\n\n", pkg.PackageName)

	buf.WriteString("import (\n")
	buf.WriteString("\t\"context\"\n")
	buf.WriteString("\t\"encoding/json\"\n")
	buf.WriteString("\n")
	fmt.Fprintf(&buf, "\t%q\n", llmPkg)
	buf.WriteString(")\n\n")

	// Suppress unused import warnings when there are no tools.
	if len(pkg.Tools) == 0 {
		buf.WriteString("// Ensure imports are used.\n")
		buf.WriteString("var (\n")
		buf.WriteString("\t_ context.Context\n")
		buf.WriteString("\t_ json.RawMessage\n")
		buf.WriteString(")\n\n")
	}

	// Generate schema variables and dispatcher functions for each tool.
	for _, tool := range pkg.Tools {
		schemaVarName := toLowerCamel(tool.FuncName) + "Schema"

		// Schema variable.
		fmt.Fprintf(&buf, "// %s is the JSON Schema for the %s tool's input.\n", schemaVarName, tool.Name)
		fmt.Fprintf(&buf, "var %s = json.RawMessage(`%s`)\n\n", schemaVarName, string(tool.InputSchema))

		// Dispatcher function.
		dispatchName := "dispatch" + tool.FuncName
		hasContext := toolHasContext(tool)

		fmt.Fprintf(&buf, "// %s is the typed dispatcher for the %s tool.\n", dispatchName, tool.Name)
		fmt.Fprintf(&buf, "// It unmarshals JSON arguments, calls the user's function, and marshals the result.\n")
		fmt.Fprintf(&buf, "func %s(ctx context.Context, argsJSON []byte) ([]byte, error) {\n", dispatchName)
		fmt.Fprintf(&buf, "\tvar input %s\n", tool.InputType)
		buf.WriteString("\tif err := json.Unmarshal(argsJSON, &input); err != nil {\n")
		buf.WriteString("\t\treturn nil, err\n")
		buf.WriteString("\t}\n")

		if hasContext {
			fmt.Fprintf(&buf, "\toutput, err := %s(ctx, &input)\n", tool.FuncName)
		} else {
			fmt.Fprintf(&buf, "\toutput, err := %s(&input)\n", tool.FuncName)
		}
		buf.WriteString("\tif err != nil {\n")
		buf.WriteString("\t\treturn nil, err\n")
		buf.WriteString("\t}\n")
		buf.WriteString("\treturn json.Marshal(output)\n")
		buf.WriteString("}\n\n")
	}

	// Registry() function.
	buf.WriteString("// Registry returns the tool registry for this package.\n")
	buf.WriteString("func Registry() *llm.Registry {\n")
	buf.WriteString("\treturn &llm.Registry{\n")
	buf.WriteString("\t\tTools: []llm.ToolDef{\n")

	for _, tool := range pkg.Tools {
		schemaVarName := toLowerCamel(tool.FuncName) + "Schema"
		dispatchName := "dispatch" + tool.FuncName

		buf.WriteString("\t\t\t{\n")
		fmt.Fprintf(&buf, "\t\t\t\tName:        %q,\n", tool.Name)
		fmt.Fprintf(&buf, "\t\t\t\tDescription: %q,\n", tool.Description)
		fmt.Fprintf(&buf, "\t\t\t\tInputSchema: %s,\n", schemaVarName)
		fmt.Fprintf(&buf, "\t\t\t\tFunc:        %s,\n", dispatchName)
		buf.WriteString("\t\t\t},\n")
	}

	buf.WriteString("\t\t},\n")
	buf.WriteString("\t}\n")
	buf.WriteString("}\n")

	formatted, err := format.Source(buf.Bytes())
	if err != nil {
		// Return unformatted source for debugging.
		return buf.Bytes(), fmt.Errorf("failed to format generated tool registry: %w", err)
	}

	return formatted, nil
}

// toolHasContext determines whether a tool function takes a context.Context
// as its first argument. We use a heuristic based on the function name and
// signature metadata. Since the static analysis doesn't capture the full
// signature, we default to true (context is the common case and the generated
// dispatcher always receives a context parameter — dropping it is harmless
// for no-context functions but calling with context on a no-context function
// won't compile).
//
// In practice, the generated dispatchers always pass context. If the user's
// function doesn't take context, the compile program build step will fail with
// a clear type error, and the user can fix their function signature.
//
// For now, we always generate the context-passing variant. A future enhancement
// could store the HasContext flag in SerializedToolInfo from the compile program.
func toolHasContext(_ llmcompile.SerializedToolInfo) bool {
	return true
}

// toLowerCamel converts a PascalCase identifier to lowerCamelCase.
// Example: "GetWeather" → "getWeather", "X" → "x".
func toLowerCamel(s string) string {
	if s == "" {
		return s
	}

	// Handle selector expressions like "otherpkg.SomeFunc".
	if idx := strings.LastIndex(s, "."); idx >= 0 {
		s = s[idx+1:]
	}

	runes := []rune(s)
	runes[0] = unicode.ToLower(runes[0])
	return string(runes)
}
